import { detectPackageManager, PackageManager } from '../detect';
import { spawnPM, SpawnResult } from '../utils/spawn';
import { isJsonMode, printJSON, printHuman } from '../utils/output';

function buildArgs(pm: PackageManager, packages: string[], dev: boolean, global: boolean): string[] {
    if (packages.length === 0) {
        return ['install'];
    }

    switch (pm) {
        case 'npm':
            return ['install', ...packages, ...(dev ? ['-D'] : []), ...(global ? ['-g'] : [])];
        case 'yarn':
            if (global) return ['global', 'add', ...packages, ...(dev ? ['-D'] : [])];
            return ['add', ...packages, ...(dev ? ['-D'] : [])];
        case 'pnpm':
            return ['add', ...packages, ...(dev ? ['-D'] : []), ...(global ? ['-g'] : [])];
        case 'bun':
            return ['add', ...packages, ...(dev ? ['-d'] : []), ...(global ? ['-g'] : [])];
    }
}

export async function install(
    packages: string[],
    options: { dev?: boolean; global?: boolean; json?: boolean }
): Promise<{ exitCode: number; pm: string; command: string }> {
    const detection = detectPackageManager();
    const args = buildArgs(detection.pm, packages, options.dev || false, options.global || false);
    const command = `${detection.pm} ${args.join(' ')}`;

    // Print command being run - but only in human mode, not JSON mode
    if (!isJsonMode()) {
        printHuman(`Running: ${command}`, 'info');
    }

    const result: SpawnResult = await spawnPM(detection.pm, args, {
        stdio: isJsonMode() ? 'pipe' : 'inherit',
    });

    const output = { exitCode: result.exitCode, pm: detection.pm, command };

    if (isJsonMode()) {
        printJSON(output);
    } else if (result.exitCode === 0) {
        printHuman('Done!', 'success');
    }

    return output;
}
